code = """import json
import re

# Load data from stored file paths
papers_file = locals()['var_functions.query_db:2']
with open(papers_file, 'r') as f:
    pa_papers = json.load(f)

print("Papers mentioning physical activity:", len(pa_papers))

# Load citations
citations_file = locals()['var_functions.query_db:4']
with open(citations_file, 'r') as f:
    citations = json.load(f)

print("Total citation records:", len(citations))

# Create title to citations mapping
citations_map = {}
for record in citations:
    title = record['title']
    count = int(record['total_citations'])
    citations_map[title] = count
    
print("Unique paper titles in citations:", len(citations_map))

# Check papers for 2016
papers_2016 = []
for paper in pa_papers:
    text = paper['text']
    if "2016" in text[:4000]:
        title_raw = paper['filename']
        title = title_raw.replace('.txt', '')
        
        # Get citation count
        citation_count = citations_map.get(title, 0)
        
        papers_2016.append({
            'title': title,
            'year': 2016,
            'total_citations': citation_count
        })

print(f"\nFound {len(papers_2016)} papers from 2016 in physical activity domain:")
for p in papers_2016:
    print(f"Title: {p['title']}")
    print(f"Citations: {p['total_citations']}")
    print()

# Return results
result = json.dumps(papers_2016, indent=2)
print('__RESULT__:')
print(result)"""

